import{_ as i,r,o as n,c as l,a as e,b as a,d as o,e as c}from"./app-52052bff.js";const s={},h=e("h2",{id:"介绍",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#介绍","aria-hidden":"true"},"#"),a(" 介绍")],-1),p={href:"https://kafka.apache.org/",target:"_blank",rel:"noopener noreferrer"},k={href:"https://github.com/apache/kafka",target:"_blank",rel:"noopener noreferrer"},d=c('<p>Kafka是最初由Linkedin公司开发，是一个分布式、支持分区的（partition）、多副本的（replica），基于zookeeper协调的分布式消息系统，用scala语言编写，Linkedin于2010年贡献给了Apache基金会并成为顶级开源项目。</p><p>Kafka的特性</p><ul><li>高吞吐量、低延迟：kafka每秒可以处理几十万条消息，它的延迟最低只有几毫秒</li><li>可扩展性：kafka集群支持热扩展</li><li>持久性、可靠性：消息被持久化到本地磁盘，并且支持数据备份防止数据丢失</li><li>容错性：允许集群中节点失败（若副本数量为n,则允许n-1个节点失败）</li><li>高并发：支持数千个客户端同时读写</li></ul><p>Kafka场景应用</p><ul><li>日志收集：一个公司可以用Kafka可以收集各种服务的log，通过kafka以统一接口服务的方式开放给各种consumer，例如hadoop、Hbase、Solr等。</li><li>消息系统：解耦和生产者和消费者、缓存消息等。</li><li>用户活动跟踪：Kafka经常被用来记录web用户或者app用户的各种活动，如浏览网页、搜索、点击等活动，这些活动信息被各个服务器发布到kafka的topic中，然后订阅者通过订阅这些topic来做实时的监控分析，或者装载到hadoop、数据仓库中做离线分析和挖掘。</li><li>运营指标：Kafka也经常用来记录运营监控数据。包括收集各种分布式应用的数据，生产各种操作的集中反馈，比如报警和报告。</li><li>流式处理：比如spark streaming和storm</li><li>事件源</li></ul><h2 id="安装" tabindex="-1"><a class="header-anchor" href="#安装" aria-hidden="true">#</a> 安装</h2>',6);function f(_,u){const t=r("ExternalLinkIcon");return n(),l("div",null,[h,e("p",null,[a("官网："),e("a",p,[a("https://kafka.apache.org/"),o(t)]),a(" github地址："),e("a",k,[a("https://github.com/apache/kafka"),o(t)])]),d])}const b=i(s,[["render",f],["__file","introduce.html.vue"]]);export{b as default};
